{
var seed = GetInt(parameters, "seed", context.Seed);
var tilesX = Math.Max(2, GetInt(parameters, "tilesX", 4));
var tilesY = Math.Max(2, GetInt(parameters, "tilesY", 4));
var irregularity = GetFloat(parameters, "irregularity", 0.3f);
var mergeChance = GetFloat(parameters, "mergeChance", 0.2f);
var gapWidth = GetFloat(parameters, "gapWidth", 0.06f);
var stoneColor = GetColor(parameters, "stoneColor", Color.FromRgb(180, 170, 155));
var gapColor = GetColor(parameters, "gapColor", Color.FromRgb(65, 60, 55));
var colorVar = GetFloat(parameters, "colorVariation", 0.2f);
var highlight = GetFloat(parameters, "highlight", 0.2f);
var shadow = GetFloat(parameters, "shadow", 0.2f);
var roughness = GetFloat(parameters, "roughness", 0.3f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var sR = stoneColor.R / 255f; var sG = stoneColor.G / 255f; var sB = stoneColor.B / 255f;
var gR = gapColor.R / 255f; var gG = gapColor.G / 255f; var gB = gapColor.B / 255f;

var cellW = 1f / tilesX;
var cellH = 1f / tilesY;
var maxJitter = Math.Min(cellW, cellH) * irregularity * 0.35f;

// Generate stone grid with optional cell merging
// merged[r,c] = (-1,-1) if not merged, or (targetR, targetC) if merged into another
var mergedInto = new (int tr, int tc)[tilesY, tilesX];
var mergedFrom = new System.Collections.Generic.List<(int r, int c)>[tilesY, tilesX];

for (var r = 0; r < tilesY; r++)
{
    for (var c = 0; c < tilesX; c++)
    {
        mergedInto[r, c] = (-1, -1);
    }
}

// Merge cells (random horizontal merges)
for (var r = 0; r < tilesY; r++)
{
    for (var c = 0; c < tilesX - 1; c++)
    {
        if (mergedInto[r, c].tr != -1) continue;
        if (mergedInto[r, c + 1].tr != -1) continue;

        var roll = HashToUnit(c * 17 + r * 13, seed + 50, 111);
        if (roll < mergeChance)
        {
            mergedInto[r, c + 1] = (r, c);
        }
    }
}

// Per-stone color and jitter
var stoneData = new (float jx, float jy, float r, float g, float b)[tilesY, tilesX];
for (var r = 0; r < tilesY; r++)
{
    for (var c = 0; c < tilesX; c++)
    {
        // Use the merged-into parent for consistent data
        var (pr, pc) = mergedInto[r, c];
        if (pr != -1)
        {
            // Share parent's data
            stoneData[r, c] = stoneData[pr, pc];
            continue;
        }

        var jx = (HashToUnit(c * 7 + r * 11, seed, 222) - 0.5f) * 2f * maxJitter;
        var jy = (HashToUnit(c * 13 + r * 5, seed + 100, 333) - 0.5f) * 2f * maxJitter;
        var hash = HashToUnit(c * 23 + r * 17, seed + 200, 444);
        var varAmt = (hash - 0.5f) * colorVar;
        stoneData[r, c] = (
            jx, jy,
            Math.Clamp(sR + varAmt, 0f, 1f),
            Math.Clamp(sG + varAmt * 0.85f, 0f, 1f),
            Math.Clamp(sB + varAmt * 0.7f, 0f, 1f)
        );
    }
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Base grid cell
    var baseCol = (int)(u / cellW);
    var baseRow = (int)(v / cellH);

    // Find actual stone (follow merge chain)
    var stoneR = baseRow;
    var stoneC = baseCol;
    // Check if this cell was merged into another
    var (mr, mc) = mergedInto[stoneR % tilesY, stoneC % tilesX];
    if (mr != -1)
    {
        stoneR = mr;
        stoneC = mc;
    }

    // Get stone center position with jitter
    var sd = stoneData[stoneR % tilesY, stoneC % tilesX];
    var cx = (stoneC + 0.5f) * cellW + sd.jx;
    var cy = (stoneR + 0.5f) * cellH + sd.jy;

    // Wrapped center-to-pixel distance
    var dx = u - cx;
    var dy = v - cy;
    if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
    if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;

    // Determine which cell range this stone occupies
    var stoneLeft = stoneC * cellW;
    var stoneRight = (mergedInto[stoneR % tilesY, stoneC % tilesX].tr != -1)
        ? (stoneC + 2) * cellW : (stoneC + 1) * cellW;
    var stoneTop = stoneR * cellH;
    var stoneBottom = (stoneR + 1) * cellH;

    // Distance to stone edges in UV space
    var leftDist = MathF.Abs(u - stoneLeft);
    var rightDist = MathF.Abs(u - stoneRight);
    var topDist = MathF.Abs(v - stoneTop);
    var bottomDist = MathF.Abs(v - stoneBottom);

    // Wrapped edge distances
    if (stoneLeft < 0f) leftDist = MathF.Min(leftDist, MathF.Abs(u - (stoneLeft + 1f)));
    if (stoneRight > 1f) rightDist = MathF.Min(rightDist, MathF.Abs(u - (stoneRight - 1f)));
    if (stoneTop < 0f) topDist = MathF.Min(topDist, MathF.Abs(v - (stoneTop + 1f)));
    if (stoneBottom > 1f) bottomDist = MathF.Min(bottomDist, MathF.Abs(v - (stoneBottom - 1f)));

    var minEdgeDist = MathF.Min(MathF.Min(leftDist, rightDist), MathF.Min(topDist, bottomDist));
    var gapHalf = gapWidth * 0.5f;

    float r, g, b;

    if (minEdgeDist < gapHalf)
    {
        // Mortar gap
        var gapNoise = TileableFractalNoise(
            u * 4f + 100f, v * 4f + 100f,
            Math.Max(1, size / 3), 1, 0.5f, 2f, seed + 300);
        var gapVar = (gapNoise - 0.5f) * 0.06f;
        r = Math.Clamp(gR + gapVar, 0f, 1f);
        g = Math.Clamp(gG + gapVar * 0.9f, 0f, 1f);
        b = Math.Clamp(gB + gapVar * 0.8f, 0f, 1f);

        // Depth shading
        var depth = (1f - minEdgeDist / gapHalf) * 0.15f;
        r = Math.Clamp(r - depth, 0f, 1f);
        g = Math.Clamp(g - depth * 0.9f, 0f, 1f);
        b = Math.Clamp(b - depth * 0.85f, 0f, 1f);
    }
    else
    {
        // Stone surface
        r = sd.r;
        g = sd.g;
        b = sd.b;

        // 3D edge shading (light from top-left)
        var edgeT = 1f - (minEdgeDist - gapHalf) / (0.5f - gapHalf);
        edgeT = MathF.Max(0f, MathF.Min(1f, edgeT));

        var lightDot = (-dx + -dy) * 0.5f;
        var hl = MathF.Max(0f, lightDot) * highlight * edgeT;
        var sh = MathF.Max(0f, -lightDot) * shadow * edgeT;

        r = Math.Clamp(r + hl - sh, 0f, 1f);
        g = Math.Clamp(g + hl * 0.85f - sh * 0.85f, 0f, 1f);
        b = Math.Clamp(b + hl * 0.7f - sh * 0.7f, 0f, 1f);

        // Surface roughness
        if (roughness > 0f)
        {
            var roughNoise = TileableFractalNoise(
                u * 6f, v * 6f,
                Math.Max(1, size / 3), 2, 0.5f, 2.5f, seed + 400);
            var rough = (roughNoise - 0.5f) * roughness * 0.08f;
            r = Math.Clamp(r + rough, 0f, 1f);
            g = Math.Clamp(g + rough * 0.9f, 0f, 1f);
            b = Math.Clamp(b + rough * 0.8f, 0f, 1f);
        }
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
